using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Convert the value to uint64_t for varint encoding
    uint64_t varint_value = static_cast<uint64_t>(value);

    // Use the writer's write_varint method to encode the value
    return writer.write_varint(varint_value);
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Use the reader's read_varint method to decode the value
    uint64_t decoded_value = reader.read_varint();

    // Convert back to the original type T
    return static_cast<T>(decoded_value);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;

    // Create a buffer adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::uint8_t>> adaptor(buffer);

    // Create a binary stream writer and reader using the adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Encode the original value
    std::size_t bytes_written = encode_varint(writer, original_value);

    // Reset the reader to the beginning of the buffer
    // Note: In a real implementation, we'd need to seek to the beginning
    // For this exam, we'll create a new reader on the same buffer

    // Create a new reader for the encoded data
    hexi::pmc::binary_stream_reader new_reader(adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(new_reader);

    // Compare the decoded value with the original
    bool success = (decoded_value == original_value);

    return success;
}
