        double converted_pressure = hexi::endian::conditional_reverse(pressure, 
            std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        adaptor.read(sensor_id);

        for (auto& temp : temperatures) {
            float read_value;
            adaptor.read(read_value);
            hexi::endian::little_to_native_inplace(read_value);
            temp = read_value;
        }

        double read_pressure;
        adaptor.read(read_pressure);
        hexi::endian::little_to_native_inplace(read_pressure);
        pressure = read_pressure;
